// // This module gates the clock signal based on the enable and test enable signals.
// It allows the clock to pass through only when both enable and test enable are high.
module register_file_clock_gate (
  input CLK,
  input EN,
  input TE,
  output ENCLK
);

  assign ENCLK = (EN & TE) ? CLK : 1'b0;

endmodule
